jwtProvider, err := jwt.New(jwt.Config{
	SecretKey:     config.GetEnvOrDefault("JWT_SECRET", "change-me-in-production"),
	Issuer:        config.GetEnvOrDefault("JWT_ISSUER", "my-app"),
	TokenTTLHours: 24,
	Logger:        appLogger,
})
if err != nil {
	appLogger.Error("failed to initialize JWT: %v", err)
}
